import React from 'react';
import { useCalendar } from '../context/CalendarContext';
import '../styles/MinimizedCalendar.css';

const MinimizedCalendar = ({ isExpanded, onToggle }) => {
    const { tasks, currentDate } = useCalendar();

    // Helper function to get days in month
    const getDaysInMonth = (date) => {
        return new Date(date.getFullYear(), date.getMonth() + 1, 0).getDate();
    };

    // Helper function to get day of week (0-6) for first day of month
    const getFirstDayOfMonth = (date) => {
        return new Date(date.getFullYear(), date.getMonth(), 1).getDay();
    };

    const renderCalendarGrid = () => {
        const daysInMonth = getDaysInMonth(currentDate);
        const firstDayOfMonth = getFirstDayOfMonth(currentDate);
        const weeks = [];
        let days = [];

        // Add empty cells for days before the first of the month
        for (let i = 0; i < firstDayOfMonth; i++) {
            days.push(<div key={`empty-${i}`} className="calendar-day empty"></div>);
        }

        // Add cells for each day of the month
        for (let day = 1; day <= daysInMonth; day++) {
            const dateStr = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
            const hasTask = tasks[dateStr]?.length > 0;
            
            days.push(
                <div 
                    key={day} 
                    className={`calendar-day ${hasTask ? 'has-task' : ''}`}
                >
                    <span className="day-number">{day}</span>
                    {hasTask && <div className="task-indicator"></div>}
                </div>
            );

            // Start new week after Saturday (6)
            if ((firstDayOfMonth + day) % 7 === 0) {
                weeks.push(<div key={weeks.length} className="calendar-week">{days}</div>);
                days = [];
            }
        }

        // Add remaining days to last week
        if (days.length > 0) {
            weeks.push(<div key={weeks.length} className="calendar-week">{days}</div>);
        }

        return (
            <div className="calendar-grid">
                <div className="weekday-header">
                    {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => (
                        <div key={day} className="weekday">{day}</div>
                    ))}
                </div>
                {weeks}
            </div>
        );
    };

    return (
        <div 
            className={`calendar-container ${isExpanded ? 'expanded' : ''}`}
            onClick={onToggle}
        >
            <div className="calendar-header">
                <span className="current-month">
                    {currentDate.toLocaleString('default', { month: 'long', year: 'numeric' })}
                </span>
                <button className="toggle-button">
                    {isExpanded ? '▼' : '▲'}
                </button>
            </div>
            <div className="calendar-content">
                {renderCalendarGrid()}
            </div>
        </div>
    );
};

export default MinimizedCalendar;
